package base;

import com.microsoft.playwright.*;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import io.qameta.allure.Allure;

/**
 * BaseTest — Base test class for all test classes
 * Manages Playwright browser lifecycle
 * Generated by: Qentrix Framework
 * Framework: Playwright Java (Hybrid)
 */
public class BaseTest {

    protected static Playwright playwright;
    protected static Browser browser;
    protected BrowserContext context;
    protected Page page;

    @BeforeEach
    public void setUp() {
        playwright = Playwright.create();
        
        String browserType = System.getenv("BROWSER");
        if (browserType == null) {
            browserType = "chromium";
        }

        boolean headless = Boolean.parseBoolean(System.getenv().getOrDefault("HEADLESS", "true"));

        BrowserType.LaunchOptions launchOptions = new BrowserType.LaunchOptions()
            .setHeadless(headless)
            .setSlowMo(50);

        switch (browserType.toLowerCase()) {
            case "firefox":
                browser = playwright.firefox().launch(launchOptions);
                break;
            case "webkit":
                browser = playwright.webkit().launch(launchOptions);
                break;
            default:
                browser = playwright.chromium().launch(launchOptions);
        }

        context = browser.newContext(new Browser.NewContextOptions()
            .setViewportSize(1920, 1080)
            .setRecordVideoDir(Paths.get("test-results/videos")));

        page = context.newPage();
        
        page.onConsoleMessage(msg -> System.out.println("Browser console: " + msg.text()));
    }

    @AfterEach
    public void tearDown() {
        if (context != null) {
            context.close();
        }
        if (browser != null) {
            browser.close();
        }
        if (playwright != null) {
            playwright.close();
        }
    }
}
